// Core
import { CloudImageCarousel } from './core/carousel'

// Styles
import cssText from './styles/index.css?inline'
import { injectStyles } from './utils/dom.utils'

injectStyles(cssText)

// Type re-exports
export type {
  CloudImageCarouselConfig,
  CloudImageCarouselInstance,
  CloudimageConfig,
  ControlsPosition,
  ImageSource,
  NormalizedImage,
  Theme,
  TransitionEffect,
} from './core/types'

// Default export — works for all consumers:
// UMD:  window.CloudImageCarousel
// ESM:  import CloudImageCarousel from '...'
// CJS:  const CloudImageCarousel = require('...').default
export default CloudImageCarousel
